import React, { useState, useEffect, useRef } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { Link } from "react-router-dom";
import {
  ChevronRight,
  ChevronUp,
  ChevronDown,
  Zap,
  Leaf,
  Clock,
  Award,
} from "lucide-react";
import gsap from "gsap";
import { ScrollTrigger } from "gsap/ScrollTrigger";

import Button from "../components/Button";
import MealCard from "../components/MealCard";
import PlanCard from "../components/PlanCard";
import ReviewCard from "../components/ReviewCard";
import { getMeals, getPlans, getReviews } from "../api/services";
import { foodImages } from "../data/foodImages";

gsap.registerPlugin(ScrollTrigger);

const Home = () => {
  const [meals, setMeals] = useState([]);
  const [plans, setPlans] = useState([]);
  const [reviews, setReviews] = useState([]);
  const [loading, setLoading] = useState(true);

  const [activeIndex, setActiveIndex] = useState(0);
  const [orbitRotation, setOrbitRotation] = useState(0);

  const popularBgRef = useRef(null);
  const plansBgRef = useRef(null);
  const reviewsBgRef = useRef(null);

  const ORBIT_RADIUS = 320;
  const ROTATION_STEP = 60;
  const ORBIT_IMAGE_COUNT = 4;

  /* ---------------- FETCH DATA ---------------- */
  useEffect(() => {
    const fetchData = async () => {
      try {
        const [mealsRes, plansRes, reviewsRes] = await Promise.all([
          getMeals(),
          getPlans(),
          getReviews(),
        ]);
        setMeals(mealsRes.data.slice(0, 6));
        setPlans(plansRes.data);
        setReviews(reviewsRes.data.slice(0, 3));
      } catch (err) {
        console.error(err);
      } finally {
        setLoading(false);
      }
    };
    fetchData();
  }, []);

  /* ---------------- AUTO ROTATING ORBIT ---------------- */
  useEffect(() => {
    const interval = setInterval(() => {
      setOrbitRotation((prev) => prev - ROTATION_STEP);
      setActiveIndex((prev) =>
        prev === foodImages.length - 1 ? 0 : prev + 1
      );
    }, 2000);

    return () => clearInterval(interval);
  }, []);

  /* ---------------- GSAP BACKGROUND PARALLAX ---------------- */
  useEffect(() => {
    gsap.fromTo(
      popularBgRef.current,
      { scale: 1.15 },
      {
        scale: 1,
        scrollTrigger: {
          trigger: popularBgRef.current,
          start: "top bottom",
          end: "bottom top",
          scrub: true,
        },
      }
    );

    gsap.fromTo(
      plansBgRef.current,
      { y: 100 },
      {
        y: -100,
        scrollTrigger: {
          trigger: plansBgRef.current,
          start: "top bottom",
          end: "bottom top",
          scrub: true,
        },
      }
    );

    gsap.fromTo(
      reviewsBgRef.current,
      { y: 150 },
      {
        y: -150,
        scrollTrigger: {
          trigger: reviewsBgRef.current,
          start: "top bottom",
          end: "bottom top",
          scrub: true,
        },
      }
    );
  }, []);

  /* ---------------- ORBIT HELPERS ---------------- */
  const handlePreviousFood = () => {
    setOrbitRotation((prev) => prev + ROTATION_STEP);
    setActiveIndex((prev) =>
      prev === 0 ? foodImages.length - 1 : prev - 1
    );
  };

  const handleNextFood = () => {
    setOrbitRotation((prev) => prev - ROTATION_STEP);
    setActiveIndex((prev) =>
      prev === foodImages.length - 1 ? 0 : prev + 1
    );
  };

  const getOrbitImages = () => {
    const images = [];
    for (let i = 0; i < ORBIT_IMAGE_COUNT; i++) {
      images.push({
        index: (activeIndex + i) % foodImages.length,
        angle: (i * 360) / ORBIT_IMAGE_COUNT,
      });
    }
    return images;
  };

  const orbitImages = getOrbitImages();
  const currentFood = foodImages[activeIndex];

  /* ---------------- ANIMATION VARIANTS ---------------- */
  const mainImageVariants = {
    enter: { opacity: 0, scale: 0.6 },
    center: { opacity: 1, scale: 1, transition: { duration: 0.6 } },
    exit: { opacity: 0, scale: 0.6, transition: { duration: 0.4 } },
  };

  const containerVariants = {
    hidden: { opacity: 0 },
    visible: {
      opacity: 1,
      transition: { staggerChildren: 0.2 },
    },
  };

  const itemVariants = {
    hidden: { opacity: 0, y: 20 },
    visible: { opacity: 1, y: 0, transition: { duration: 0.5 } },
  };

  const whyFeatures = [
    { icon: Zap, title: "High Protein", description: "Fuel your workouts." },
    { icon: Leaf, title: "Fresh Ingredients", description: "Daily sourced." },
    { icon: Clock, title: "Quick Delivery", description: "30 min delivery." },
    { icon: Award, title: "Certified Nutrition", description: "Expert planned." },
  ];

  return (
    <div className="bg-neutral-bg">
      {/* ---------------- HERO SECTION ---------------- */}
      <section className="relative min-h-screen bg-white overflow-hidden pt-20">
        <div className="relative z-10 max-w-7xl mx-auto grid lg:grid-cols-2 gap-12 items-center px-6">
          <motion.div initial={{ x: -50, opacity: 0 }} animate={{ x: 0, opacity: 1 }}>
            <h1 className="text-6xl font-bold">Delicious</h1>
            <h2 className="text-5xl text-green-600 font-bold mb-6">
              Kill the Hunger
            </h2>
            <p className="text-gray-600 mb-6 max-w-lg">
              Premium healthy meals delivered fresh to your door.
            </p>
            <Button>Order Now</Button>
          </motion.div>

          <div className="relative flex items-center justify-center">
            <motion.div animate={{ rotate: orbitRotation }}>
              {orbitImages.map((item, i) => {
                const rad = (item.angle * Math.PI) / 180;
                const x = Math.cos(rad) * ORBIT_RADIUS;
                const y = Math.sin(rad) * ORBIT_RADIUS;

                return (
                  <div
                    key={i}
                    className="absolute"
                    style={{
                      transform: `translate(${x}px, ${y}px)`,
                    }}
                  >
                    <img
                      src={foodImages[item.index].image}
                      alt=""
                      className="w-24 h-24 rounded-full shadow-lg"
                    />
                  </div>
                );
              })}
            </motion.div>

            <AnimatePresence mode="wait">
              <motion.img
                key={activeIndex}
                variants={mainImageVariants}
                initial="enter"
                animate="center"
                exit="exit"
                src={currentFood.image}
                className="w-80 h-80 rounded-full shadow-2xl"
              />
            </AnimatePresence>

            <div className="absolute right-0 flex flex-col gap-4">
              <button onClick={handlePreviousFood}><ChevronUp /></button>
              <button onClick={handleNextFood}><ChevronDown /></button>
            </div>
          </div>
        </div>
      </section>

      {/* ---------------- WHY GALOBA ---------------- */}
      <section className="py-20 px-6">
        <motion.div
          className="grid md:grid-cols-4 gap-6 max-w-7xl mx-auto"
          variants={containerVariants}
          initial="hidden"
          whileInView="visible"
        >
          {whyFeatures.map((f, i) => (
            <motion.div key={i} variants={itemVariants} className="bg-white p-6 rounded-xl shadow">
              <f.icon className="text-green-600 mb-3" size={32} />
              <h3 className="font-bold">{f.title}</h3>
              <p className="text-gray-600">{f.description}</p>
            </motion.div>
          ))}
        </motion.div>
      </section>

      {/* ---------------- POPULAR MEALS ---------------- */}
      <section className="relative py-20 px-6">
        <div ref={popularBgRef} className="absolute inset-0 bg-cover bg-center"
          style={{ backgroundImage: "url('https://images.unsplash.com/photo-1504674900247-087703934569')" }}>
          <div className="absolute inset-0 bg-black/60" />
        </div>

        <div className="relative max-w-7xl mx-auto grid md:grid-cols-3 gap-8">
          {meals.map((meal) => (
            <MealCard key={meal.id} meal={meal} />
          ))}
        </div>
      </section>

      {/* ---------------- SUBSCRIPTIONS ---------------- */}
      <section className="relative py-20 px-6">
        <div ref={plansBgRef} className="absolute inset-0 bg-gray-100" />
        <div className="relative max-w-7xl mx-auto grid md:grid-cols-3 gap-8">
          {plans.map((plan, i) => (
            <PlanCard key={plan.id} plan={plan} isPopular={i === 1} />
          ))}
        </div>
      </section>

      {/* ---------------- REVIEWS ---------------- */}
      <section className="relative py-20 px-6">
        <div ref={reviewsBgRef} className="absolute inset-0 bg-black/80" />
        <div className="relative max-w-7xl mx-auto grid md:grid-cols-3 gap-8 text-white">
          {reviews.map((review) => (
            <ReviewCard key={review.id} review={review} />
          ))}
        </div>
      </section>
    </div>
  );
};

export default Home;
